class Solution:
    def platesBetweenCandles(self, s, queries):
        n = len(s)
        res = []
        for l, r in queries:
            L = -1
            for i in range(l, r + 1):
                if s[i] == '|':
                    L = i
                    break
            if L == -1:
                res.append(0)
                continue
            R = -1
            for i in range(r, l - 1, -1):
                if s[i] == '|':
                    R = i
                    break
            if L >= R:
                res.append(0)
                continue
            count = 0
            for i in range(L + 1, R):
                if s[i] == '*':
                    count += 1
            res.append(count)
        return res

