class Solution:
    def platesBetweenCandles(self, s, queries):
        n = len(s)
        prefix = [0] * (n + 1)
        for i, ch in enumerate(s):
            prefix[i + 1] = prefix[i] + (1 if ch == '*' else 0)
        next_candle = [-1] * n
        last = -1
        for i in range(n - 1, -1, -1):
            if s[i] == '|':
                last = i
            next_candle[i] = last
        prev_candle = [-1] * n
        last = -1
        for i in range(n):
            if s[i] == '|':
                last = i
            prev_candle[i] = last
        res = []
        for l, r in queries:
            L = next_candle[l]
            R = prev_candle[r]
            if L == -1 or R == -1 or L >= R:
                res.append(0)
            else:
                res.append(prefix[R + 1] - prefix[L])
        return res

