var platesBetweenCandles = function(s, queries) {
    const n = s.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + (s[i] === '*' ? 1 : 0);
    }
    const nextCandle = new Array(n).fill(-1);
    let last = -1;
    for (let i = n - 1; i >= 0; i--) {
        if (s[i] === '|') last = i;
        nextCandle[i] = last;
    }
    const prevCandle = new Array(n).fill(-1);
    last = -1;
    for (let i = 0; i < n; i++) {
        if (s[i] === '|') last = i;
        prevCandle[i] = last;
    }
    const res = [];
    for (const [l, r] of queries) {
        const L = nextCandle[l];
        const R = prevCandle[r];
        if (L === -1 || R === -1 || L >= R) {
            res.push(0);
        } else {
            res.push(prefix[R + 1] - prefix[L]);
        }
    }
    return res;
};
